"use strict";class Webinar{constructor(e,t,n,s){$.getJSON(`${API_BASE_URL}/connect/contact/webinar/${e}`).done(e=>{s.name=e.name,s.status=e.status,s.language=n[e.language],s.dateStart=e.dateStart.replace(" ","T")+"Z",s.lead=e.metadata.lead[t],s.learnTitle=e.metadata.learn.title[t],s.learnItems=e.metadata.learn.items.map(e=>e[t])}).fail(e=>{console.error("Fetching webinar data failed:",e.responseJSON?.message||e.statusText)})}static formatBerlin(e,t){return new Intl.DateTimeFormat(document.documentElement.lang||"en",{timeZone:"Europe/Berlin",...t}).format(new Date(e))}}